BEGIN {
    first_heading = 1
    toc_content = ""
}

/^#+[[:space:]]+/ {
    # Extract heading level and text
    match($0, /^(#+)[[:space:]]+(.*)/, arr)
    level = arr[1]
    text = arr[2]

    # Skip the first heading
    if (first_heading == 1) {
        first_heading = 0
        print $0
        next
    }

    # Convert to anchor: lowercase and replace spaces with hyphens
    anchor = tolower(text)
    gsub(/[[:space:]]/, "-", anchor)

    # Build TOC entry
    if (level == "##") {
        toc_content = toc_content "  - [" text "](#" anchor ")\n"
    } else {
        toc_content = toc_content "- [" text "](#" anchor ")\n"
    }

    # Store line to print later
    lines_after_first[NR] = $0
    next
}

{
    lines_after_first[NR] = $0
}

END {
    # Print first heading and TOC
    for (i in lines_after_first) {
        if (i == 1) {
            print lines_after_first[1]
        }
    }
    print ""
    print "## Table of Contents"
    print ""
    printf toc_content

    # Print remaining content
    for (i in lines_after_first) {
        if (i > 1) {
            print lines_after_first[i]
        }
    }
}
EOF

