# Create a simple merge script
(
# Start with defaults
cat /config/defaults.ini

# Add a marker
echo "# === CUSTOM OVERRIDES START ==="

# Add custom (with section headers)
cat /config/custom.ini
) > /tmp/combined.txt

# Now process to merge properly
awk '
BEGIN {
    current_section = ""
}

# Skip the marker line
/^# === CUSTOM OVERRIDES START/ { skip = 1; next }

# If we are past the marker, we are in custom section
skip {
    custom_section = 1
}

# Handle section headers
/^\[/ {
    section = substr($0, 2, length($0) - 2)
    if (!custom_section) {
        # In defaults phase
        if (!(section in defaults_sections)) {
            defaults_sections[section] = 1
            section_order[++num_sections] = section
        }
        current_section = section
        section_type = "defaults"
    } else {
        # In custom phase
        current_section = section
        section_type = "custom"
    }
    next
}

# Skip comments and empty lines in custom section (we processed them in defaults)
custom_section && /^[[:space:]]*$/ { next }

# Handle key=value pairs
/^[^[#;].*=/ {
    if (current_section == "") next

    key = $0
    sub(/=.*/, "", key)
    gsub(/^ +| +$/, "", key)

    value = $0
    sub(/^[^=]*=/, "", value)

    if (section_type == "defaults") {
        if (!(current_section in defaults_keys)) {
            defaults_keys[current_section] = 0
        }
        defaults_keys[current_section]++
        key_order[current_section][defaults_keys[current_section]] = key
        config[current_section][key] = value
    } else {
        config[current_section][key] = value
    }
    next
}

END {
    for (i = 1; i <= num_sections; i++) {
        section = section_order[i]
        print "[" section "]"
        for (j = 1; j <= defaults_keys[section]; j++) {
            key = key_order[section][j]
            print key "=" config[section][key]
        }
        print ""
    }
}
' /tmp/combined.txt > /config/merged.ini

